/*! three.js local vendor loader for Aqwat Training Platform.
 * This file keeps the repository folder structure compatible with module pages that load ../vendor/three.min.js.
 * It loads Three.js r128 from CDN when the full local vendor bundle is not committed.
 */
(function () {
  if (window.THREE) return;
  document.write('<script src="https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js"><\/script>');
})();
